/** @internal */
interface SegmentsPresetProps {
  uiPreset: SegmentsPresetType;
  id: string;
  pinLimitReached: boolean;
  isPinned: boolean;
  isSelected: boolean;
}

/** @internal */
export const expandAndCollapseAnimationVariants = {
  enter: {
    height: 'auto',
    opacity: 1,
    translateY: 0,
    transition: {
      duration: AnimationsJS.ExpandCollapse.Duration.Base,
      ease: expandCollapseEasing,
    },
  },
  exit: {
    height: 0,
    opacity: 0,
    translateY: -10,
    transition: {
      duration: AnimationsJS.ExpandCollapse.Duration.Base,
      ease: expandCollapseEasing,
    },
  },
};

/**
 * @internal
 */
const SegmentsPresetText = ({
  segment,
  isFirst,
}: {
  segment: FilterSegment;
  isFirst: boolean;
}) => {
  const andText = (
    <Text textStyle="base" className={styles.and}>
      &nbsp;
      <FormattedMessage
        defaultMessage="and"
        description="Text that is separating between multiple Segments in one preset."
        id="GeQL1Mbr4RzmlFJk"
      />
      &nbsp;
    </Text>
  );

  const connectingString = isFirst ? '' : andText;

  return (
    <Fragment key={segment.id}>
      {connectingString}
      <SegmentText segment={segment} />
    </Fragment>
  );
};

function usePinningTooltipText(
  pinLimitReached: boolean,
  isPinned: boolean,
): string {
  const intl = useIntl();

  if (pinLimitReached && !isPinned) {
    return intl.formatMessage({
      defaultMessage: "You can't pin more than 10 items.",
      id: 'Y/6wwuz1ueL+7V2j',
      description: 'Tooltip text for pinning limit.',
    });
  }

  if (!isPinned) {
    return intl.formatMessage(
      {
        defaultMessage: 'Pin in {appName}',
        id: 'RPdRdtDJumoOO3os',
        description: 'Tooltip text for pin button.',
      },
      { appName: getAppName() },
    );
  }

  return intl.formatMessage({
    defaultMessage: 'Unpin',
    id: 'uCbwlgMp2BNGzNro',
    description: 'Text for the unpin button of a segment preset.',
  });
}

function updateCachePinMutation(
  old: UserSegmentsPresets,
  id: string,
  segments: FilterSegment[],
): UserSegmentsPresets {
  // We always want to add the newly pinned one at the top.
  const pinnedPresets = old.pinnedPresets;
  pinnedPresets.unshift({ id, segments });

  return {
    ...old,
    pinnedPresets,
  };
}

function updateCacheUnpinMutation(
  old: UserSegmentsPresets,
  id: string,
): UserSegmentsPresets {
  const pinnedPresets = old.pinnedPresets;
  const pinnedPresetIndex = pinnedPresets.findIndex(
    (preset) => preset.id === id,
  );

  if (pinnedPresetIndex === -1) {
    return old;
  }

  pinnedPresets.splice(pinnedPresetIndex, 1);

  return {
    recentPresets: old.recentPresets,
    pinnedPresets,
  };
}

/**
 * @internal
 */
const PresetTooltipText = ({ segments }: { segments: FilterSegment[] }) => {
  return (
    <Flex flexDirection="column" gap={4}>
      {segments.map((segment) => {
        return (
          <SegmentText
            key={segment.id}
            segment={segment}
            variableClassName={textStyleCSS({
              fontStyle: 'text',
              textStyle: 'small',
            })}
          />
        );
      })}
    </Flex>
  );
};

/**
 * @internal
 */
const SegmentText = ({
  segment,
  variableClassName,
}: {
  segment: FilterSegment;
  variableClassName?: string;
}) => {
  const { getSegment } = useSegmentsCache();
  const intl = useIntl();
  const { data } = useQuery(
    {
      queryKey: ['getSegment', segment.id],
      queryFn: () => getSegment(segment.id),
      notifyOnChangeProps: ['dataUpdatedAt'],
    },
    segmentsClient.queryClient,
  );

  let variables = '';
  if (segment.variables && segment.variables.length > 0) {
    variables = `: ${segment.variables[0].values
      .map((variable) => getReadableValue(variable, intl))
      .join(', ')}`;
  }

  if (variableClassName) {
    return (
      <span>
        {data?.segment.name ?? segment.id}
        <span className={variableClassName}>{variables}</span>
      </span>
    );
  }

  return `${data?.segment.name ?? segment.id}${variables}`;
};

/**
 * LoadingState-component for SegmentSelector Overlay
 * @internal
 */
export const SegmentsPreset = (props: SegmentsPresetProps) => {
  const shouldReduceMotion = useReducedMotion();
  const {
    uiPreset,
    id,
    isPinned,
    isSelected,
    pinLimitReached,
  }: SegmentsPresetProps = props;
  const { segments } = uiPreset;
  const [isAnimating, setIsAnimating] = useState(false);

  const { setUISegments } = useSegmentsUIContext();
  const { overlayState } = useContext(UISegmentsDispatchContext);
  const { setSegments } = useSegments();

  const pin = useMutation(
    {
      mutationKey: ['pin-segment-preset', id],
      mutationFn: pinSegmentsPreset,
      onMutate: async () =>
        runOptimisticMutation<UserSegmentsPresets>(
          'getSegmentsPresets',
          (prevState) => updateCachePinMutation(prevState, id, segments),
          [
            'pin-segment-preset',
            'unpin-segment-preset',
            id,
            'getSegmentsPresets',
          ],
        ),
      onError: (error, _, context) =>
        handleFailedOptimisticMutation('getSegmentsPresets', error, context),
      onSettled: () =>
        handleSettledOptimisticMutation(
          ['getSegmentsPresets'],
          ['pin-segment-preset', 'unpin-segment-preset', id],
        ),
    },
    segmentsClient.queryClient,
  );

  const unpin = useMutation(
    {
      mutationKey: ['unpin-segment-preset', id],
      mutationFn: unpinSegmentsPreset,
      onMutate: async () =>
        runOptimisticMutation<UserSegmentsPresets>(
          'getSegmentsPresets',
          (prevState) => updateCacheUnpinMutation(prevState, id),
          [
            'pin-segment-preset',
            'unpin-segment-preset',
            id,
            'getSegmentsPresets',
          ],
        ),
      onError: (error, _, context) =>
        handleFailedOptimisticMutation('getSegmentsPresets', error, context),
      onSettled: () =>
        handleSettledOptimisticMutation(
          ['getSegmentsPresets'],
          ['pin-segment-preset', 'unpin-segment-preset', id],
        ),
    },
    segmentsClient.queryClient,
  );

  const applyPreset = useMutation(
    {
      mutationKey: ['apply-segment-preset', id],
      mutationFn: () => {
        // We changed the syntax of the values, formerly they could be a stringified array and now we flatten any arrays inside.
        // Some of the presets still follow the old syntax, so we need to convert them here before applying.
        const flattenedSegments = segments.map((segment) => {
          if (segment.variables) {
            const flattenedVariables = segment.variables.map((variable) => {
              const values = flattenQueryResultToValues([], variable.values);

              return {
                ...variable,
                values,
              };
            });

            return { ...segment, variables: flattenedVariables };
          }

          return segment;
        });

        setUISegments(flattenedSegments, true);
        return setSegments(flattenedSegments);
      },
      onSuccess: async () => {
        const isValid = await areUiSegmentsValid(segments);
        if (isValid) {
          overlayState?.close();
        }
      },
    },
    segmentsClient.queryClient,
  );

  const color = isSelected ? 'primary' : 'neutral';

  const pinningTooltipText = usePinningTooltipText(pinLimitReached, isPinned);
  const icon = isPinned ? <PinOffIcon /> : <PinIcon />;
  const pinButtonDataDtProperties = `state:${isPinned ? 'unpin' : 'pin'}`;

  const onClick = () =>
    isPinned ? unpin.mutate(uiPreset.id) : pin.mutate(segments);

  const labelRef = useRef<HTMLDivElement>(null);
  const [showTooltip, setShowTooltip] = useState(false);
  const stackingContext = useOverlayStacking(undefined, 'overlay');

  return (
    <motion.div
      variants={shouldReduceMotion ? {} : expandAndCollapseAnimationVariants}
      initial="exit"
      animate="enter"
      exit="exit"
      className={clsx({
        [animationHelperStyles.isAnimating]: isAnimating,
      })}
      onAnimationStart={() => setIsAnimating(true)}
      onAnimationComplete={() => setIsAnimating(false)}
    >
      <InputGroup
        className={clsx([
          styles.inputGroup,
          { [styles.inputGroupSelected]: isSelected },
        ])}
      >
        <Tooltip
          placement="left"
          fallbackPlacements={['top', 'bottom', 'right']}
          text={<PresetTooltipText segments={segments} />}
          open={showTooltip}
          onOpenChange={(isOpen) => {
            const hasOverFlow =
              (labelRef.current?.scrollWidth ?? 0) >
              (labelRef.current?.clientWidth ?? 0);

            setShowTooltip(isOpen && hasOverFlow);
          }}
          className={textStyleCSS({
            fontStyle: 'text',
            textStyle: 'small-emphasized',
          })}
          style={{ zIndex: Number(stackingContext.style.zIndex) + 1 }}
        >
          <Button
            color={color}
            width="100%"
            textAlign="start"
            className={clsx(styles.presetButton, {
              [styles.selectionMark]: isSelected,
            })}
            onClick={() => applyPreset.mutate()}
          >
            <Button.Label className={styles.buttonLabel} ref={labelRef}>
              {segments.map((segment, index) => (
                <SegmentsPresetText
                  segment={segment}
                  isFirst={index === 0}
                  key={segment.id}
                />
              ))}
            </Button.Label>
          </Button>
        </Tooltip>
        <Tooltip
          placement="right"
          text={pinningTooltipText}
          className={textStyleCSS({
            fontStyle: 'text',
            textStyle: 'small-emphasized',
          })}
          style={{ zIndex: Number(stackingContext.style.zIndex) + 1 }}
        >
          <Button
            color={color}
            className={styles.suffixButton}
            onClick={onClick}
            disabled={pinLimitReached && !isPinned}
            aria-label={pinningTooltipText}
            data-dt-name="PinUnpin"
            data-dt-properties={pinButtonDataDtProperties}
          >
            {icon}
          </Button>
        </Tooltip>
      </InputGroup>
    </motion.div>
  );
};
